begin;\n\nalter table public.profiles add column if not exists developer_reputation numeric(3,2) not null default 0;\nalter table public.profiles drop constraint if exists profiles_developer_reputation_check;\nalter table public.profiles add constraint profiles_developer_reputation_check check (developer_reputation >= 0 and developer_reputation <= 5);\n\ncreate or replace function public.recalculate_profile_reputations(p_profile_id uuid)\nreturns void\nlanguage plpgsql\nsecurity definer\nset search_path=public\nas $$\ndeclare\n  v_approved integer := 0;\n  v_helpful integer := 0;\n  v_tests_received integer := 0;\n  v_avg_rating numeric := 0;\n  v_avg_review_hours numeric := null;\n  v_tester numeric := 0;\n  v_developer numeric := 0;\nbegin\n  select count(*)::integer, count(*) filter (where fr.developer_helpful=true)::integer\n  into v_approved, v_helpful\n  from public.campaign_members cm\n  left join public.feedback_reports fr on fr.campaign_member_id=cm.id\n  where cm.tester_id=p_profile_id and cm.status='approved';\n\n  if v_approved > 0 then\n    v_tester := least(5.0, round((2.50 + least(v_approved,20)*0.10 + least(v_helpful,10)*0.05)::numeric,2));\n  end if;\n\n  select count(cm.id)::integer, coalesce(avg(fr.overall_rating),0), avg(extract(epoch from (fr.reviewed_at-cm.submitted_at))/3600.0)\n  into v_tests_received, v_avg_rating, v_avg_review_hours\n  from public.projects p\n  join public.testing_campaigns c on c.project_id=p.id\n  join public.campaign_members cm on cm.campaign_id=c.id and cm.status='approved'\n  left join public.feedback_reports fr on fr.campaign_member_id=cm.id\n  where p.owner_id=p_profile_id;\n\n  if v_tests_received > 0 then\n    v_developer := 2.25 + least(v_tests_received,25)*0.06 + least(greatest(v_avg_rating-3,0),2)*0.35;\n    if v_avg_review_hours is not null then\n      v_developer := v_developer + case when v_avg_review_hours <= 48 then 0.55 when v_avg_review_hours <= 168 then 0.25 else 0 end;\n    end if;\n    v_developer := least(5.0, round(v_developer::numeric,2));\n  end if;\n\n  update public.profiles set tester_reputation=v_tester, developer_reputation=v_developer, updated_at=now() where id=p_profile_id;\nend;\n$$;\nrevoke all on function public.recalculate_profile_reputations(uuid) from public,anon,authenticated;\n\ncreate or replace function public.refresh_related_reputations()\nreturns trigger\nlanguage plpgsql\nsecurity definer\nset search_path=public\nas $$\ndeclare\n  v_member_id uuid;\n  v_tester uuid;\n  v_owner uuid;\nbegin\n  if tg_table_name='campaign_members' then v_member_id:=coalesce(new.id,old.id); else v_member_id:=coalesce(new.campaign_member_id,old.campaign_member_id); end if;\n  select cm.tester_id,p.owner_id into v_tester,v_owner\n  from public.campaign_members cm join public.testing_campaigns c on c.id=cm.campaign_id join public.projects p on p.id=c.project_id\n  where cm.id=v_member_id;\n  if v_tester is not null then perform public.recalculate_profile_reputations(v_tester); end if;\n  if v_owner is not null then perform public.recalculate_profile_reputations(v_owner); end if;\n  return coalesce(new,old);\nend;\n$$;\n\ndrop trigger if exists refresh_reputation_after_member_change on public.campaign_members;\ncreate trigger refresh_reputation_after_member_change after insert or update of status,approved_at on public.campaign_members for each row execute function public.refresh_related_reputations();\ndrop trigger if exists refresh_reputation_after_feedback_change on public.feedback_reports;\ncreate trigger refresh_reputation_after_feedback_change after insert or update of developer_helpful,overall_rating,reviewed_at on public.feedback_reports for each row execute function public.refresh_related_reputations();\n\ndo $$ declare r record; begin for r in select id from public.profiles loop perform public.recalculate_profile_reputations(r.id); end loop; end $$;\n\ncreate or replace function public.wall_of_fame_v3(p_limit integer default 10)\nreturns jsonb\nlanguage sql\nstable\nsecurity definer\nset search_path=public\nas $$\nwith approved as (\n  select cm.id,cm.tester_id,cm.approved_at,c.project_id,fr.overall_rating,fr.developer_helpful\n  from public.campaign_members cm join public.testing_campaigns c on c.id=cm.campaign_id\n  left join public.feedback_reports fr on fr.campaign_member_id=cm.id where cm.status='approved'\n),\ntester_stats as (\n  select pr.id,pr.username,pr.display_name,pr.avatar_url,pr.tester_reputation,pr.created_at,count(a.id)::integer approved_tests,\n  count(a.id) filter(where a.approved_at>=date_trunc('month',now()))::integer monthly_tests,\n  count(a.id) filter(where a.developer_helpful=true)::integer helpful_feedback,100.0::numeric approval_rate\n  from public.profiles pr left join approved a on a.tester_id=pr.id where coalesce(pr.account_status,'active')='active' group by pr.id\n),\ndeveloper_stats as (\n  select pr.id,pr.username,pr.display_name,pr.avatar_url,pr.developer_reputation,pr.created_at,count(distinct p.id)::integer published_projects,\n  count(distinct a.id)::integer approved_tests_received,round(avg(a.overall_rating),2) average_rating,count(distinct pu.id)::integer devlog_count\n  from public.profiles pr join public.projects p on p.owner_id=pr.id and p.is_published=true and p.moderation_status='visible'\n  left join approved a on a.project_id=p.id left join public.project_updates pu on pu.project_id=p.id and pu.is_published=true\n  where coalesce(pr.account_status,'active')='active' group by pr.id\n),\nproject_stats as (\n  select p.id,p.slug,p.name,p.icon_url,p.platform,p.last_activity_at,count(distinct a.id)::integer approved_tests,\n  count(distinct a.id) filter(where a.approved_at>=date_trunc('month',now()))::integer monthly_tests,round(avg(a.overall_rating),2) average_rating,\n  count(distinct pu.id)::integer devlog_count,count(distinct pu.id) filter(where pu.created_at>=date_trunc('month',now()))::integer monthly_devlogs\n  from public.projects p left join approved a on a.project_id=p.id left join public.project_updates pu on pu.project_id=p.id and pu.is_published=true\n  where p.is_published=true and p.moderation_status='visible' group by p.id\n),\ncommunity as (\n  select ts.id,ts.username,ts.display_name,ts.avatar_url,ts.approved_tests,coalesce(ds.published_projects,0) published_projects,ts.helpful_feedback,\n  (ts.approved_tests*5+ts.helpful_feedback*3+coalesce(ds.published_projects,0)*8+coalesce(ds.devlog_count,0)*2)::integer community_score\n  from tester_stats ts join developer_stats ds on ds.id=ts.id where ts.approved_tests>=3 and ds.published_projects>=1\n)\nselect jsonb_build_object(\n 'testers',coalesce((select jsonb_agg(to_jsonb(x) order by x.rank) from (select row_number() over(order by tester_reputation desc,approved_tests desc,helpful_feedback desc) rank,id,username,display_name,avatar_url,tester_reputation,approved_tests,helpful_feedback,approval_rate,case when tester_reputation>=4.5 then 'Trusted Tester' when approved_tests>=10 then 'Top Tester' else 'Rising Tester' end badge from tester_stats where approved_tests>=3 order by tester_reputation desc,approved_tests desc limit greatest(1,least(coalesce(p_limit,10),25)))x),'[]'::jsonb),\n 'developers',coalesce((select jsonb_agg(to_jsonb(x) order by x.rank) from (select row_number() over(order by developer_reputation desc,approved_tests_received desc,average_rating desc nulls last) rank,id,username,display_name,avatar_url,developer_reputation,published_projects,approved_tests_received,average_rating,devlog_count,case when developer_reputation>=4.5 then 'Trusted Developer' when approved_tests_received>=10 then 'Featured Developer' else 'Active Developer' end badge from developer_stats where approved_tests_received>=3 order by developer_reputation desc,approved_tests_received desc limit greatest(1,least(coalesce(p_limit,10),25)))x),'[]'::jsonb),\n 'projects',coalesce((select jsonb_agg(to_jsonb(x) order by x.rank) from (select row_number() over(order by approved_tests desc,average_rating desc nulls last,last_activity_at desc) rank,id,slug,name,icon_url,platform,approved_tests,average_rating,devlog_count,case when approved_tests>=20 and coalesce(average_rating,0)>=4 then 'Hall of Fame Project' else 'Top Project' end badge from project_stats where approved_tests>=3 and average_rating is not null order by approved_tests desc,average_rating desc nulls last limit greatest(1,least(coalesce(p_limit,10),25)))x),'[]'::jsonb),\n 'monthly_projects',coalesce((select jsonb_agg(to_jsonb(x) order by x.rank) from (select row_number() over(order by monthly_tests desc,average_rating desc nulls last,monthly_devlogs desc) rank,id,slug,name,icon_url,platform,monthly_tests,average_rating,monthly_devlogs,case when row_number() over(order by monthly_tests desc,average_rating desc nulls last,monthly_devlogs desc)=1 then 'Project of the Month' else 'Trending Project' end badge from project_stats where monthly_tests>0 or monthly_devlogs>0 order by monthly_tests desc,average_rating desc nulls last limit greatest(1,least(coalesce(p_limit,10),25)))x),'[]'::jsonb),\n 'monthly_testers',coalesce((select jsonb_agg(to_jsonb(x) order by x.rank) from (select row_number() over(order by monthly_tests desc,helpful_feedback desc,tester_reputation desc) rank,id,username,display_name,avatar_url,monthly_tests,helpful_feedback,tester_reputation,case when row_number() over(order by monthly_tests desc,helpful_feedback desc,tester_reputation desc)=1 then 'Tester of the Month' else 'Monthly Leader' end badge from tester_stats where monthly_tests>0 order by monthly_tests desc,helpful_feedback desc limit greatest(1,least(coalesce(p_limit,10),25)))x),'[]'::jsonb),\n 'community_champions',coalesce((select jsonb_agg(to_jsonb(x) order by x.rank) from (select row_number() over(order by community_score desc,approved_tests desc) rank,id,username,display_name,avatar_url,approved_tests,published_projects,helpful_feedback,community_score,'Community Champion'::text badge from community order by community_score desc limit greatest(1,least(coalesce(p_limit,10),25)))x),'[]'::jsonb)\n);\n$$;\nrevoke all on function public.wall_of_fame_v3(integer) from public;\ngrant execute on function public.wall_of_fame_v3(integer) to anon,authenticated;\n\ncommit;\n